
.panel {
  width: 100%;
  max-width: 680px;
  background: var(--c-bg-dark);
  border: 2px solid var(--c-border);
  border-radius: 4px;
  color: var(--c-text);
  font-size: 13px;
  line-height: 1.4;
  margin: 0 auto;
  overflow: hidden;
}

.header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 10px 14px;
  background: var(--c-bg-card);
  border-bottom: 2px solid var(--c-primary);
}

.title {
  font-weight: bold;
  font-size: 15px;
  color: var(--c-text-bright);
  letter-spacing: 1px;
}

.zone {
  font-size: 12px;
  color: var(--c-accent);
  background: rgba(243, 156, 18, 0.1);
  padding: 2px 8px;
  border-radius: 2px;
  border: 1px solid rgba(243, 156, 18, 0.3);
}

/* 主角状态条 */
.commander-bar {
  display: flex;
  gap: 6px;
  padding: 8px 14px;
  background: var(--c-bg-panel);
  border-bottom: 1px solid var(--c-border);
}

.stat-item {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
}

.stat-label {
  font-size: 10px;
  color: var(--c-text-muted);
}

.stat-value {
  font-weight: bold;
  font-size: 14px;
  color: var(--c-text-bright);
}

.merit-gold { color: #f1c40f !important; text-shadow: 0 0 6px rgba(241,196,15,0.5); }
.merit-silver { color: #bdc3c7 !important; }
.merit-bronze { color: #e67e22 !important; }

/* 战果统计 */
.stats-row {
  display: flex;
  gap: 4px;
  padding: 8px 14px;
}

.stat-chip {
  flex: 1;
  display: flex;
  align-items: center;
  gap: 4px;
  background: var(--c-bg-card);
  border: 1px solid var(--c-border);
  border-radius: 3px;
  padding: 5px 8px;
  font-size: 11px;
}

.chip-icon { font-size: 13px; }
.chip-label { color: var(--c-text-muted); }
.chip-num { margin-left: auto; font-weight: bold; color: var(--c-text-bright); font-size: 14px; }
.streak-on { color: var(--c-accent) !important; }

/* 小队区域 */
.section-label {
  font-size: 12px;
  font-weight: bold;
  color: var(--c-accent);
  padding: 6px 14px 4px;
  letter-spacing: 1px;
}

.empty-hint {
  padding: 12px 14px;
  color: var(--c-text-muted);
  font-style: italic;
  font-size: 12px;
}

.squad-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
  gap: 6px;
  padding: 4px 14px 10px;
}

.member-card {
  background: var(--c-bg-card);
  border: 1px solid var(--c-border);
  border-radius: 3px;
  overflow: hidden;
}

.mem-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 6px 8px;
  background: var(--c-bg-panel);
  border-bottom: 1px solid var(--c-border);
}

.mem-name {
  font-weight: bold;
  color: var(--c-text-bright);
}

.mem-type {
  font-size: 10px;
  padding: 1px 5px;
  border-radius: 2px;
  color: #fff;
}
.tp-assault { background: rgba(231,76,60,0.7); }
.tp-scout { background: rgba(52,152,219,0.7); }
.tp-guerrilla { background: rgba(46,204,113,0.7); }
.tp-heavy { background: rgba(155,89,182,0.7); }

.mem-body {
  padding: 6px 8px;
}

.mem-row {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-bottom: 4px;
  &:last-child { margin-bottom: 0; }
}

.mem-key {
  font-size: 10px;
  color: var(--c-text-muted);
  min-width: 24px;
}

.mem-status {
  font-size: 11px;
  font-weight: bold;
  padding: 1px 6px;
  border-radius: 2px;
}
.st-ok { color: var(--c-status-normal); }
.st-light { color: var(--c-status-light); }
.st-heavy { color: var(--c-status-heavy); }
.st-broken { color: var(--c-status-broken); }

/* 好感度 */
.aff-num {
  font-size: 12px;
  font-weight: bold;
  color: var(--c-text-bright);
}

.source-row {
  margin-top: 2px;
  font-size: 10px;
}
.mem-source {
  color: var(--c-text-muted);
  &.recruit { color: var(--c-accent-blue); }
}

/* 仓库 */
.inventory-grid {
  display: flex;
  flex-wrap: wrap;
  gap: 4px;
  padding: 4px 14px 10px;
}

.item-chip {
  display: flex;
  align-items: center;
  gap: 4px;
  background: var(--c-bg-card);
  border: 1px solid var(--c-border);
  border-radius: 3px;
  padding: 3px 8px;
  font-size: 11px;
}

.item-type-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
}
.it-weapon { background: var(--c-accent-red); }
.it-ammo { background: var(--c-accent); }
.it-part { background: var(--c-accent-blue); }
.it-consume { background: var(--c-accent-green); }
.it-other { background: var(--c-text-muted); }

.item-name { color: var(--c-text); }
.item-qty { font-weight: bold; color: var(--c-text-bright); }

/* 成员详情 */
.mem-intro {
  font-size: 10px;
  color: var(--c-accent);
  font-style: italic;
  padding-top: 2px;
  border-top: 1px dashed var(--c-border);
  margin-top: 2px;
}
.mem-detail-toggle {
  display: block !important;
  font-size: 11px;
  color: var(--c-accent-blue);
  cursor: pointer;
  text-align: center;
  padding: 4px 0;
  border-top: 1px solid var(--c-border);
  margin-top: 4px;
  user-select: none;
  &:hover { color: var(--c-text-bright); background: var(--c-bg-panel); }
}
.mem-detail {
  background: var(--c-bg-dark);
  border: 1px solid var(--c-border);
  border-radius: 2px;
  padding: 6px 8px;
  margin-top: 2px;
}
.detail-line {
  font-size: 10px;
  line-height: 1.5;
  margin-bottom: 3px;
  color: var(--c-text);
  &:last-child { margin-bottom: 0; }
}
.detail-label {
  color: var(--c-accent);
  font-weight: bold;
  margin-right: 4px;
}
.detail-pending {
  color: var(--c-text-muted);
  font-style: italic;
}
